import csv

questions = [
  {"id":"4159","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Equacoes exponenciais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A solucao da equacao 3^x = 81 e:","alternativa_a":"x = 4","alternativa_b":"x = 3","alternativa_c":"x = 27","alternativa_d":"x = 9","alternativa_e":"x = 2","resposta_correta":"a","explicacao":"3^x = 81 = 3^4, logo x = 4.","resposta":""},
  {"id":"4160","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Equacoes logaritmicas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A solucao de log(x) = 2 (logaritmo base 10) e:","alternativa_a":"x = 100","alternativa_b":"x = 20","alternativa_c":"x = 10","alternativa_d":"x = 1000","alternativa_e":"x = 0,01","resposta_correta":"a","explicacao":"log10(x) = 2 => x = 10^2 = 100.","resposta":""},
  {"id":"4161","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Espacial","subtema":"Volume da esfera","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma esfera tem raio 3 cm. Seu volume e (pi=3,14):","alternativa_a":"113,04 cm3","alternativa_b":"37,68 cm3","alternativa_c":"28,26 cm3","alternativa_d":"56,52 cm3","alternativa_e":"339,12 cm3","resposta_correta":"a","explicacao":"V = (4/3) x pi x r^3 = (4/3) x 3,14 x 27 = 4 x 3,14 x 9 = 113,04 cm3.","resposta":""},
  {"id":"4162","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Espacial","subtema":"Volume do cone","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um cone tem raio de base 3 cm e altura 4 cm. Seu volume e (pi=3,14):","alternativa_a":"37,68 cm3","alternativa_b":"113,04 cm3","alternativa_c":"12,56 cm3","alternativa_d":"75,36 cm3","alternativa_e":"25,12 cm3","resposta_correta":"a","explicacao":"V = (1/3) x pi x r^2 x h = (1/3) x 3,14 x 9 x 4 = (1/3) x 113,04 = 37,68 cm3.","resposta":""},
  {"id":"4163","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Semelhanca de triangulos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Dois triangulos semelhantes tem lados correspondentes de 3 e 6. A razao de semelhanca e:","alternativa_a":"1:2","alternativa_b":"1:3","alternativa_c":"2:1","alternativa_d":"3:6","alternativa_e":"1:4","resposta_correta":"a","explicacao":"Razao de semelhanca = menor/maior = 3/6 = 1/2, ou seja, 1:2.","resposta":""},
  {"id":"4164","tipo":"multipla","disciplina":"Fisica","tema":"Termodinamica","subtema":"Ciclo de Carnot","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O Ciclo de Carnot e importante em termodinamica porque:","alternativa_a":"Representa a eficiencia maxima teorica possivel para uma maquina termica entre duas temperaturas","alternativa_b":"E o ciclo usado em todos os motores a combustao interna","alternativa_c":"Determina a velocidade media das moleculas em um gas","alternativa_d":"Estabelece que a entropia total do universo decresce","alternativa_e":"Permite converter 100% do calor em trabalho","resposta_correta":"a","explicacao":"O Ciclo de Carnot (proposto por Sadi Carnot em 1824) e um ciclo reversivel ideal composto por dois processos isometricos e dois adiabáticos. Sua eficiencia eta = 1 - Tc/Th e o limite superior para qualquer maquina termica real operando entre as temperaturas Tc e Th. Nenhuma maquina real pode superar a eficiencia de Carnot (Segunda Lei da Termodinamica).","resposta":""},
  {"id":"4165","tipo":"multipla","disciplina":"Fisica","tema":"Ondulatoria","subtema":"Reflexao e refracao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Lei de Snell (Snell-Descartes) descreve:","alternativa_a":"A relacao entre angulos de incidencia e refracao quando a luz passa entre meios diferentes","alternativa_b":"A reflexao total interna da luz","alternativa_c":"A difusao da luz em particulas","alternativa_d":"A absorcao da luz por materiais","alternativa_e":"A polarizacao da luz por superficies","resposta_correta":"a","explicacao":"A Lei de Snell: n1 * sen(theta1) = n2 * sen(theta2), onde n1 e n2 sao os indices de refracao dos meios e theta1, theta2 sao os angulos de incidencia e refracao em relacao a normal. Quando a luz passa de meio menos denso para mais denso, aproxima-se da normal. Explica fenomenos como a aparencia quebrada de um palito na agua.","resposta":""},
  {"id":"4166","tipo":"multipla","disciplina":"Fisica","tema":"Eletromagnetismo","subtema":"Ondas eletromagneticas","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O espectro eletromagnetico, em ordem crescente de frequencia (e energia), inclui:","alternativa_a":"Radio, micro-ondas, infravermelho, luz visivel, ultravioleta, raios-X, raios gama","alternativa_b":"Raios gama, raios-X, ultravioleta, visivel, infravermelho, micro-ondas, radio","alternativa_c":"Luz visivel, radio, raios-X, infravermelho","alternativa_d":"Radio, luz visivel, raios-X, gama","alternativa_e":"Infravermelho, ultravioleta, visivel, radio","resposta_correta":"a","explicacao":"O espectro EM vai de baixas frequencias (radio) a altissimas (gama): Radio < Micro-ondas < Infravermelho < Luz visivel < Ultravioleta < Raios-X < Raios gama. Maiores frequencias = maior energia (E = hf) e menor comprimento de onda (c = lambda x f). Raios gama e raios-X sao ionizantes (alta energia); radio e micro-ondas sao nao ionizantes.","resposta":""},
  {"id":"4167","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Eletrizacao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A lei de Coulomb estabelece que a forca eletrica entre duas cargas e:","alternativa_a":"Proporcional ao produto das cargas e inversamente proporcional ao quadrado da distancia","alternativa_b":"Proporcional a distancia entre as cargas","alternativa_c":"Independente da magnitude das cargas","alternativa_d":"Diretamente proporcional ao cubo da distancia","alternativa_e":"Constante independente da distancia","resposta_correta":"a","explicacao":"F = k * |q1 * q2| / r^2, onde k = 9x10^9 N.m^2/C^2. Cargas do mesmo sinal se repelem; sinais opostos se atraem. A estrutura matematica e identica a Lei de Gravitacao Universal de Newton (ambas seguem a lei do inverso do quadrado da distancia).","resposta":""},
  {"id":"4168","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Isomeros","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Isotopos sao atomos do mesmo elemento que diferem no:","alternativa_a":"Numero de neutrons (mesmo numero atomico, diferente numero de massa)","alternativa_b":"Numero de protons","alternativa_c":"Numero de eletrons","alternativa_d":"Numero de orbital","alternativa_e":"Tipo de ligacao quimica","resposta_correta":"a","explicacao":"Isotopos de um mesmo elemento tem o mesmo numero atomico Z (mesmo numero de protons = mesmo elemento) mas diferente numero de massa A (diferente numero de neutrons). Exemplo: C-12, C-13 e C-14 sao isotopos do carbono (Z=6): 6 protons mas 6, 7 e 8 neutrons respectivamente.","resposta":""},
  {"id":"4169","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Fermentacao","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A fermentacao alcoolica, usada na producao de bebidas e biocombustivel, transforma:","alternativa_a":"Glicose em etanol e CO2 (por leveduras, sem oxigenio)","alternativa_b":"Etanol em glicose e agua","alternativa_c":"CO2 e H2O em glicose e O2","alternativa_d":"Amido em celulase e lipase","alternativa_e":"Proteinas em aminoacidos","resposta_correta":"a","explicacao":"Fermentacao alcoolica: C6H12O6 -> 2C2H5OH + 2CO2 + 2ATP. Realizada por leveduras (Saccharomyces cerevisiae) em condicoes anaérobicas. O etanol produzido e o alcool das bebidas e tambem o etanol combustivel (biocombustivel). O CO2 produzido e responsavel pela fermentacao do pao e pelas bolhas das bebidas.","resposta":""},
  {"id":"4170","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Nomenclatura de sais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O composto NaCl e denominado:","alternativa_a":"Cloreto de sodio","alternativa_b":"Clorito de sodio","alternativa_c":"Hipoclorito de sodio","alternativa_d":"Clorato de sodio","alternativa_e":"Perclorato de sodio","resposta_correta":"a","explicacao":"NaCl e cloreto de sodio (sal de cozinha). Nomenclatura dos sais: 'eto/ato + de + cation'. O Cl- e o ion cloreto (do acido cloridrico HCl). Nao confundir: ClO- = hipoclorito; ClO2- = clorito; ClO3- = clorato; ClO4- = perclorato.","resposta":""},
  {"id":"4171","tipo":"multipla","disciplina":"Biologia","tema":"Genetica","subtema":"Cromossomos sexuais","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Em humanos, o sexo biologico e determinado pelos cromossomos sexuais. Uma mulher tipicamente possui:","alternativa_a":"Dois cromossomos X (XX)","alternativa_b":"Um X e um Y (XY)","alternativa_c":"Apenas um X (X0)","alternativa_d":"Dois Y (YY)","alternativa_e":"Tres X (XXX)","resposta_correta":"a","explicacao":"O sistema de determinacao sexual humano: femeas tipicas = XX; machos tipicos = XY. O cromossomo Y contem o gene SRY que direciona o desenvolvimento do testiculo e do sexo masculino. Variacoes existem: Sindrome de Turner (X0), Klinefelter (XXY), etc. Os gametas femininos sempre contem X; os masculinos podem conter X ou Y.","resposta":""},
  {"id":"4172","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Sucessao ecologica","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A sucessao ecologica primaria ocorre quando:","alternativa_a":"A colonizacao inicia em ambiente sem vida previa, como rochas nuas ou dunas de areia","alternativa_b":"Um ecossistema perturbado (queimada, desmatamento) e recolonizado","alternativa_c":"Especies exoticas invadem um ecossistema nativo","alternativa_d":"A populacao de uma especie atinge seu pico","alternativa_e":"A biodiversidade de um ecossistema atinge o maximo","resposta_correta":"a","explicacao":"Sucessao primaria: inicia em substratos sem solo ou materia organica previa (rochas, lavas, dunas). Organismos pioneiros (liquens, musgos) preparam o substrato, criando condicoes para especies mais complexas. E lenta (seculos a milenios). A sucessao secundaria ocorre apos disturbio em area ja colonizada (queimada, desmatamento), sendo mais rapida por ja haver solo e banco de sementes.","resposta":""},
  {"id":"4173","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Visao e audicao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A parte do olho responsavel pela focagem das imagens na retina e:","alternativa_a":"Cristalino (lente do olho)","alternativa_b":"Cornea","alternativa_c":"Iris","alternativa_d":"Pupila","alternativa_e":"Esclerótica","resposta_correta":"a","explicacao":"O cristalino e uma lente biconvexa flexivel localizada atras da pupila. Seu formato e controlado pelos musculos ciliares: para focar objetos proximos, os musculos se contraem e o cristalino se torna mais esférico (maior poder de refracao); para objetos distantes, os musculos relaxam e o cristalino achata. Esse processo e chamado de acomodacao visual.","resposta":""},
  {"id":"4174","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"China contemporanea","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Revolucao Chinesa de 1949, liderada por Mao Zedong, estabeleceu:","alternativa_a":"A Republica Popular da China, com partido comunista no poder","alternativa_b":"Uma democracia representativa multipartidaria","alternativa_c":"Uma monarquia constitucional","alternativa_d":"Uma federacao de republicas autonomas","alternativa_e":"A Republica da China sob Chiang Kai-shek","resposta_correta":"a","explicacao":"Em 1o de outubro de 1949, Mao Zedong proclamou a Republica Popular da China apos a vitoria do Partido Comunista (PCC) na guerra civil contra o Kuomintang (Chiang Kai-shek, que se refugiou em Taiwan). A China comunista adotou inicialmente o modelo sovietico, depois desenvolveu uma via propria (Maoismo). Atualmente e uma grande potencia economica com sistema politico de partido unico.","resposta":""},
  {"id":"4175","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Descolonizacao da Asia","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Mahatma Gandhi liderou o movimento de independencia da India com a estrategia da:","alternativa_a":"Resistencia nao-violenta (satyagraha) — desobediencia civil e boicote","alternativa_b":"Guerrilha armada contra o exercito britanico","alternativa_c":"Alianca com o Partido Comunista Internacional","alternativa_d":"Negociacao diplomatica exclusiva com o Parlamento britanico","alternativa_e":"Alianca com o Paquistao e Bangladesh contra o colonialismo","resposta_correta":"a","explicacao":"Gandhi desenvolveu o satyagraha ('forca da verdade/alma') — resistencia nao-violenta baseada na desobediencia civil, boicote a produtos britanicos, greves e acoes pasivas de massa. Exemplos: Marcha do Sal (1930), movimento Quit India (1942). Demonstrou que e possivel resistir a um imperio sem violencia. Influenciou Martin Luther King Jr. e Nelson Mandela.","resposta":""},
  {"id":"4176","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Lula e PT","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Luis Inacio Lula da Silva foi eleito presidente do Brasil pela primeira vez em:","alternativa_a":"2002, assumindo em 2003","alternativa_b":"1989, em disputa com Collor","alternativa_c":"1994, perdendo para FHC","alternativa_d":"1998, perdendo para FHC","alternativa_e":"2006, em segundo mandato","resposta_correta":"a","explicacao":"Lula foi eleito presidente em outubro de 2002 (4a tentativa), derrotando Jose Serra (PSDB) no segundo turno. Assumiu em 1o de janeiro de 2003, representando a primeira vez que a esquerda chegava ao poder federal no Brasil. Governou dois mandatos (2003-2006 e 2007-2010). Sua presidencia foi marcada por programas sociais (Bolsa Familia, Fome Zero) e crescimento economico.","resposta":""},
  {"id":"4177","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Periodo Jango e Reformas de Base","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As Reformas de Base propostas por Joao Goulart em 1963-64 incluiam:","alternativa_a":"Reforma agraria, educacional, fiscal e bancaria — com forte resistencia das elites conservadoras","alternativa_b":"Privatizacoes e abertura ao capital estrangeiro","alternativa_c":"Modernizacao militar e compra de armamentos","alternativa_d":"Criacao de zonas de livre comercio","alternativa_e":"Reforma constitucional para implantacao do presidencialismo","resposta_correta":"a","explicacao":"Joao Goulart ('Jango') propôs reformas estruturais para democratizar o acesso a terra, reducao da remessa de lucros ao exterior, reforma universitaria, legalizacao do PCB e extensao do direito de voto a analfabetos e militares de baixa patente. O comicio da Central do Brasil (13/03/1964) com 200.000 pessoas foi o apice do movimento. As reformas foram o principal pretexto para o golpe de 1o de abril de 1964.","resposta":""},
  {"id":"4178","tipo":"multipla","disciplina":"Geografia","tema":"Transportes","subtema":"Matriz de transportes","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Brasil caracteriza-se por uma matriz de transportes com predominancia do modal:","alternativa_a":"Rodoviario, com subutilizacao do ferroviario e hidroviario","alternativa_b":"Ferroviario, herdado do periodo colonial","alternativa_c":"Hidroviario, aproveitando os grandes rios","alternativa_d":"Aereo, devido ao tamanho do territorio","alternativa_e":"Maritimo de cabotagem","resposta_correta":"a","explicacao":"O Brasil tem ~65% de sua carga transportada por estradas (modal rodoviario), heranca das politicas desenvolvimentistas de JK (Plano de Metas, 1956-60) que priorizaram a industria automobilistica e as rodovias. Isso e ineficiente para um pais de dimensao continental: ferrovias e hidrovia sao mais baratas para grandes volumes a longas distancias. A deficiencia ferroviaria e um dos gargalos da competitividade brasileira.","resposta":""},
  {"id":"4179","tipo":"multipla","disciplina":"Geografia","tema":"Industria","subtema":"Industria brasileira","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O processo de industrializacao brasileira, intensificado no governo Vargas, seguiu o modelo de:","alternativa_a":"Substituicao de importacoes — producao nacional substituindo produtos importados","alternativa_b":"Exportacao de produtos industrializados para o mercado mundial","alternativa_c":"Artesanato e pequenas manufacfaturas regionais","alternativa_d":"Industrializacao baseada em tecnologia nacional exclusivamente","alternativa_e":"Privatizacao de empresas estatais","resposta_correta":"a","explicacao":"O modelo de industrializacao por substituicao de importacoes (ISI) dominou o desenvolvimento brasileiro de 1930 a 1980. O governo criou empresas estatais estrategicas (CSN, Petrobras, Vale do Rio Doce) e protegeu a industria nacional com tarifas e cambio controlado. O objetivo era produzir internamente o que antes era importado, reduzindo vulnerabilidade externa e gerando empregos.","resposta":""},
  {"id":"4180","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Regencia nominal","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A regencia nominal correta e:","alternativa_a":"'Tenho certeza DE que venceremos' (certeza DE algo)","alternativa_b":"'Tenho certeza QUE venceremos' (sem preposicao)","alternativa_c":"'Ele e simpatico com todos' (simpatico COM)","alternativa_d":"'Estou ciente de que aconteceu' e 'ciente a que'","alternativa_e":"'Preferivel A' e 'preferivel DE'","resposta_correta":"a","explicacao":"Regencia nominal: substantivos, adjetivos e adverbios exigem preposicoes especificas. 'Certeza DE algo' — o correto e 'tenho certeza DE que'. 'Simpatico A' (nao 'com'). 'Ciente DE'. 'Preferivel A' (nao 'do que'). A crase pode aparecer antes do pronome relativo: 'a certeza a que me refiro' (nao confundir com a locucao verbal 'certeza de que').","resposta":""},
  {"id":"4181","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Semantica","subtema":"Polissemia e homonimia","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Polissemia refere-se a:","alternativa_a":"Uma unica palavra com varios significados relacionados entre si por extensao semantica","alternativa_b":"Duas palavras diferentes com o mesmo som e grafias semelhantes","alternativa_c":"Palavras com significados opostos","alternativa_d":"Palavras de mesma grafia mas significados completamente distintos","alternativa_e":"Substituto de uma palavra por sinônimo","resposta_correta":"a","explicacao":"Polissemia: uma palavra com varios significados que guardam relacao semantica entre si (extensao do sentido original). Ex: 'manga' — fruta, parte da camisa, tipo de filtro. Homonimia: palavras com mesma forma mas sem relacao de significado (homografas: 'ele come' / 'come' = penhasco; homofonas: 'acender'/'ascender'). Antonimia: opostos. Sinonimia: mesmo significado.","resposta":""},
  {"id":"4182","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Regionalismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Grande Sertao: Veredas (1956), de Joao Guimaraes Rosa, e considerada a maior obra da prosa modernista brasileira por:","alternativa_a":"Fundir linguagem sertaneja, invencao lexical, filosofia existencial e narrador ambiguo (Riobaldo)","alternativa_b":"Retratar fielmente o sertao nordestino com linguagem jornalistica","alternativa_c":"Introduzir o Realismo Magico na literatura brasileira","alternativa_d":"Ser a primeira obra em prosa do Modernismo","alternativa_e":"Denunciar a seca e a miseria do sertao","resposta_correta":"a","explicacao":"'Grande Sertao: Veredas' e uma obra total: Riobaldo, narrador-protagonista, conta sua vida de jagunco a um interlocutor silencioso. A linguagem e a grande revolucao: fusao de elementos do sertao mineiro com neologismos, arcaismos e invencao criativa. O tema central e o pacto com o diabo (existiu ou nao?), a dualidade bem/mal, a identidade. Guimaraes Rosa criou uma nova lingua literaria portuguesa.","resposta":""},
  {"id":"4183","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Politica","subtema":"Marxismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A base e a superestrutura no marxismo referem-se a:","alternativa_a":"Base = estrutura economica (relacoes de producao); superestrutura = Estado, direito, religiao, ideologia","alternativa_b":"Base = povo e trabalhadores; superestrutura = burguesia e capitalistas","alternativa_c":"Base = infraestrutura material (estradas, portos); superestrutura = industria","alternativa_d":"Base = ciencia e tecnologia; superestrutura = cultura popular","alternativa_e":"Base = forca de trabalho; superestrutura = capital","resposta_correta":"a","explicacao":"No materialismo historico de Marx: a 'base' (ou infraestrutura) e o conjunto das relacoes de producao — quem possui os meios de producao e como o trabalho e organizado. A 'superestrutura' e o conjunto das instituicoes politicas, juridicas, religiosas e ideologicas que derivam da base e a legitimam. A base determina a superestrutura, mas nao mecanicamente — ha relativa autonomia e dialética.","resposta":""},
  {"id":"4184","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia da Mente","subtema":"Funcionalismo","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O funcionalismo em filosofia da mente sustenta que:","alternativa_a":"Os estados mentais sao definidos por suas funcoes causais — relacoes inputs, outputs e outros estados","alternativa_b":"A mente e identica ao cerebro","alternativa_c":"Nao existe mente separada do corpo","alternativa_d":"A mente e o result de relacoes sociais","alternativa_e":"Os estados mentais sao ilusioes da consciencia","resposta_correta":"a","explicacao":"O funcionalismo (Putnam, Fodor) afirma que os estados mentais sao definidos por seus papeis funcionais — o que causam (inputs: sensacoes), o que produzem (outputs: comportamentos) e suas relacoes com outros estados mentais — independente do substrato fisico que os implementa. Uma calculadora e um cerebro podem ter o mesmo estado funcional. Isso permite a possibilidade de inteligencia artificial e mentes em substratos nao biologicos.","resposta":""},
  {"id":"4185","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Violencia","subtema":"Violencia urbana","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A perspectiva sociologica sobre a violencia urbana no Brasil destaca que ela e produto de:","alternativa_a":"Exclusao social, desigualdade, trafego de drogas, falha do Estado e ausencia de oportunidades","alternativa_b":"Fatores geneticos e biologicos das populacoes marginalizadas","alternativa_c":"Influencia cultural estrangeira","alternativa_d":"Excesso de liberdades democraticas","alternativa_e":"Problema exclusivo de cidades grandes","resposta_correta":"a","explicacao":"A violencia urbana no Brasil tem causas estruturais: extrema desigualdade economica (Gini alto), exclusao social, trafego de drogas (economia ilicita em areas sem oportunidades), ausencia ou corrupcao do Estado nas periferias, legado da escravidao (discriminacao racial), e encarceramento em massa que retroalimenta as organizacoes criminosas. Nao e um fenomeno natural ou inato.","resposta":""},
  {"id":"4186","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Comunicacao","subtema":"Midias sociais","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As camaras de eco (echo chambers) em midias sociais referem-se a:","alternativa_a":"Ambientes digitais que amplificam crenças preexistentes ao expor usuarios apenas a conteudos alinhados com suas visoes","alternativa_b":"Tecnologia de audio utilizada em transmissoes ao vivo","alternativa_c":"Grupos de midia corporativa que controlam narrativas","alternativa_d":"Bolhas financeiras criadas por influenciadores digitais","alternativa_e":"Sistemas de censura algoritmica de conteudos","resposta_correta":"a","explicacao":"Camaras de eco (echo chambers) e bolhas de filtro (filter bubbles) sao fenomenos das midias sociais onde os algoritmos mostram apenas conteudos alinhados com as preferencias do usuario, reforçando preconceitos e crenças sem expor a visoes divergentes. Contribuem para a polarizacao politica, desinformacao e dificuldade de dialogo democratico. Eli Pariser cunhou o termo 'filter bubble' em 2011.","resposta":""},
  {"id":"4187","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Fracao e porcentagem","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Quanto e 15% de 200?","alternativa_a":"30","alternativa_b":"15","alternativa_c":"3","alternativa_d":"300","alternativa_e":"1500","resposta_correta":"a","explicacao":"15% de 200 = (15/100) x 200 = 0,15 x 200 = 30.","resposta":""},
  {"id":"4188","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Regra de tres","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Se 3 operarios constroem 15 metros de muro em um dia, quantos metros constroem 5 operarios no mesmo tempo?","alternativa_a":"25 metros","alternativa_b":"45 metros","alternativa_c":"9 metros","alternativa_d":"75 metros","alternativa_e":"30 metros","resposta_correta":"a","explicacao":"Proporcao direta: 3/15 = 5/x => x = (5 x 15)/3 = 75/3 = 25 metros.","resposta":""},
  {"id":"4189","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Angulos","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A soma dos angulos internos de um triangulo e:","alternativa_a":"180 graus","alternativa_b":"360 graus","alternativa_c":"90 graus","alternativa_d":"270 graus","alternativa_e":"Depende do tipo de triangulo","resposta_correta":"a","explicacao":"A soma dos angulos internos de qualquer triangulo e sempre 180 graus. Para qualquer poligono convexo de n lados, a soma e (n-2) x 180. Para o quadrilatero: (4-2) x 180 = 360 graus; pentagono: 540 graus, etc.","resposta":""},
  {"id":"4190","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Movimentos circulares","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um objeto em movimento circular uniforme tem aceleracao centripeta que aponta para:","alternativa_a":"O centro do circulo (aceleracao centripeta)","alternativa_b":"A tangente do circulo","alternativa_c":"Para fora do circulo (aceleracao centrifuga)","alternativa_d":"Na direcao do movimento","alternativa_e":"Verticalmente para baixo","resposta_correta":"a","explicacao":"No MCU (Movimento Circular Uniforme), a velocidade e constante em modulo mas muda de direcao. Isso implica aceleracao centripeta (ac = v^2/r) apontando para o centro do circulo, perpendicular a velocidade. A 'forca centrifuga' e uma forca ficticia (sentida em referenciais nao inerciais rotativos) — nao e real no referencial inercial.","resposta":""},
  {"id":"4191","tipo":"multipla","disciplina":"Fisica","tema":"Eletricidade","subtema":"Geradores eletricos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Um gerador ideal converte:","alternativa_a":"Energia mecanica (ou quimica/nuclear) em energia eletrica","alternativa_b":"Energia eletrica em energia mecanica","alternativa_c":"Calor em luz","alternativa_d":"Energia quimica em energia mecanica","alternativa_e":"Luz em energia cinetica","resposta_correta":"a","explicacao":"Geradores eletricos convertem energia mecanica (alternadores, dínamos) em eletrica. Pilhas e baterias convertem quimica em eletrica. Paineis solares convertem luminosa em eletrica. Motores eletricos fazem o inverso dos geradores: convertem eletrica em mecanica. Resistencias e lampadas incandescentes convertem eletrica em calor/luz.","resposta":""},
  {"id":"4192","tipo":"multipla","disciplina":"Quimica","tema":"Bioquimica","subtema":"Enzimas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As enzimas sao catalisadores biologicos que:","alternativa_a":"Aceleram reacoes quimicas sem serem consumidas, diminuindo a energia de ativacao","alternativa_b":"Produzem energia quimica na celula","alternativa_c":"Transportam oxigenio no sangue","alternativa_d":"Fornecem energia a curto prazo","alternativa_e":"Controlam a expressao dos genes","resposta_correta":"a","explicacao":"Enzimas sao proteinas (ou RNA — ribozimas) que catalisam reacoes bioquimicas: (1) aumentam a velocidade das reacoes (ate 10^17 vezes mais rapidas); (2) sao especificas para seu substrato (chave-fechadura / encaixe induzido); (3) nao sao consumidas no processo; (4) reduzem a energia de ativacao. Temperatura, pH e inibidores afetam sua atividade.","resposta":""},
  {"id":"4193","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Metais e ametais","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Qual das seguintes propriedades e caracteristica dos metais?","alternativa_a":"Alta condutividade eletrica e termica, brilho metalico e maleabilidade","alternativa_b":"Baixa condutividade eletrica e alta volatilidade","alternativa_c":"Carater ionico predominante em suas ligacoes","alternativa_d":"Tendencia a receber eletrons (alta eletronegatividade)","alternativa_e":"Existencia no estado gasoso a temperatura ambiente","resposta_correta":"a","explicacao":"Os metais tipicamente possuem: (1) alta condutividade eletrica (eletrons livres no modelo do mar de eletrons); (2) alta condutividade termica; (3) brilho metalico; (4) maleabilidade (podem ser laminados) e ductilidade (podem ser estirados em fios); (5) tendem a perder eletrons (baixa eletronegatividade) formando ions positivos (cations). Mercurio e excecao: e liquido a 25C.","resposta":""},
  {"id":"4194","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema digestivo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A digestao quimica dos lipidios (gorduras) ocorre principalmente no:","alternativa_a":"Intestino delgado, com a bile (do figado) e a lipase pancreatica","alternativa_b":"Estomago, pela pepsina","alternativa_c":"Boca, pela amilase salivar","alternativa_d":"Intestino grosso, por bacterias","alternativa_e":"Esofago","resposta_correta":"a","explicacao":"Os lipidios sao digeridos principalmente no intestino delgado. A bile (produzida pelo figado, armazenada na vesicula biliar) emulsifica as gorduras (quebra em gotinulas menores). A lipase pancreatica hidrolisa os trigliceridos em acidos graxos e glicerol, que sao absorvidos pelos enterocitos e entram nos vasos linfaticos (quiliferos).","resposta":""},
  {"id":"4195","tipo":"multipla","disciplina":"Biologia","tema":"Botanica","subtema":"Tipos de raiz","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A funcao principal da raiz nas plantas e:","alternativa_a":"Fixar a planta ao solo e absorver agua e sais minerais","alternativa_b":"Realizar fotossintese","alternativa_c":"Produzir flores e frutos","alternativa_d":"Realizar a transpiracao","alternativa_e":"Armazenar energia luminosa","resposta_correta":"a","explicacao":"A raiz tem tres funcoes principais: (1) Fixacao da planta ao substrato; (2) Absorcao de agua e sais minerais dissolvidos do solo (pelos pelos absorventes das raizes) — seiva bruta; (3) Conducao dessa seiva ao caule pelo xilema. Algumas raizes tem funcoes adicionais: armazenamento (batata-doce), respiracao (manguezais), etc. A fotossintese e funcao das folhas.","resposta":""},
  {"id":"4196","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Colonizacao da America","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O sistema de exploracao colonial portugues no Brasil baseou-se inicialmente no(a):","alternativa_a":"Extrativismo do pau-brasil com trabalho indigena remunerado e depois no ciclo da cana-de-acucar com trabalho escravizado","alternativa_b":"Mineracao intensa desde o inicio","alternativa_c":"Pecuaria extensiva no litoral","alternativa_d":"Comercio de escravizados diretamente com a Europa","alternativa_e":"Agricultura de subsistencia pelos colonos","resposta_correta":"a","explicacao":"A colonizacao portuguesa no Brasil passou por fases: (1) Ciclo do pau-brasil (1500-1530): extrativismo baseado no escambo com indigenas; (2) Ciclo da cana-de-acucar (1530-1650): agriculutra de exportacao com trabalho escravizado africano no Nordeste; (3) Ciclo do ouro (1690-1760): mineracao em Minas Gerais; (4) Ciclo do cafe (sec. XIX): Sao Paulo e Vale do Paraiba.","resposta":""},
  {"id":"4197","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Contestado","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A Guerra do Contestado (1912-1916) foi um conflito no Sul do Brasil que envolveu:","alternativa_a":"Sertanejos caboclos contra latifundiarios e o Estado, em disputa por terras e com forte componente religioso","alternativa_b":"Conflito entre Brasil e Argentina pela fronteira","alternativa_c":"Revolta de escravizados recentemente libertos","alternativa_d":"Conflito entre fazendeiros e tropas federais","alternativa_e":"Movimento de independencia do Estado de Santa Catarina","resposta_correta":"a","explicacao":"A Guerra do Contestado foi uma revolta popular messiânica no planalto catariense e paranaense. Caboclos desalojados de suas terras pela construcao da Estrada de Ferro Sao Paulo-Rio Grande (pelos americanos da Brazil Railway) se organizaram em comunidades lideradas por monges (Jose Maria). O Estado e os latifundiarios sufocariam o movimento com violencia extrema — 8.000 a 20.000 mortos. Contemporanea de Canudos, mas menos conhecida.","resposta":""},
  {"id":"4198","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Welfare State","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O Estado de Bem-Estar Social (Welfare State), desenvolvido principalmente na Europa Ocidental apos 1945, caracterizou-se por:","alternativa_a":"Amplos servicos publicos de saude, educacao, previdencia e habitacao financiados pelo Estado","alternativa_b":"Livre mercado sem intervencao estatal","alternativa_c":"Economia planificada centralizada pelo Estado","alternativa_d":"Distribuicao igualitaria dos meios de producao","alternativa_e":"Eliminacao da propriedade privada","resposta_correta":"a","explicacao":"O Welfare State emergiu no pos-guerra com o Keynesianismo e o pacto social democratico. O Estado assumiu responsabilidade pelo bem-estar cidadao: saude publica (NHS britanico, 1948), previdencia, educacao gratuita, habitacao, seguro-desemprego. Atingiu seu auge nos 'Trinta Gloriosos' (1945-1975). Entrou em crise com o choque do petroleo e o neoliberalismo thatcherista/reaganista nos anos 1980.","resposta":""},
  {"id":"4199","tipo":"multipla","disciplina":"Geografia","tema":"Geopolitica","subtema":"Multipolaridade","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A ordem multipolar emergente no seculo XXI e caracterizada por:","alternativa_a":"Disputas entre multiplos centros de poder (EUA, China, UE, Russia, India) sem hegemonia unica","alternativa_b":"Dominio absoluto dos EUA como unica superpotencia","alternativa_c":"Retorno a bipolaridade da Guerra Fria","alternativa_d":"Governanca global pacifica por organismos internacionais","alternativa_e":"Predominio da Europa e do Japo na economia mundial","resposta_correta":"a","explicacao":"Apos a breve unipolaridade americana (1991-2001), emergiu uma ordem multipolar: China ascendeu como segunda economia mundial, desafiando a hegemonia americana; Russia reafirmou influencia regional; India cresce como potencia; UE como bloco economico influente. Esse multipolarismo gera tensoes (guerra comercial EUA-China, invasao da Ucrania) mas tambem novas coalizoes (BRICS, SCO).","resposta":""},
  {"id":"4200","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Redacao","subtema":"Parafrase e resumo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A parafrases diferencia-se do plagio porque:","alternativa_a":"Reescreve as ideias do texto original com outras palavras, preservando o sentido e atribuindo a autoria","alternativa_b":"Copia literalmente o texto original com alteracoes minimas","alternativa_c":"Resume o texto em poucas palavras","alternativa_d":"Transcreve o texto original com aspas e citacao","alternativa_e":"Critica e refuta as ideias do texto original","resposta_correta":"a","explicacao":"A parafrases e a reescrita do conteudo de um texto com palavras proprias, mantendo o sentido e sempre indicando a fonte (autoria). Difere do plagio (copia sem atribuicao) e da citacao direta (transcricao literal com aspas). Difere tambem do resumo (reducao do texto) e da resenha (resumo + critica). A parafrases demonstra compreensao do texto, nao memorizacao.","resposta":""},
  {"id":"4201","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Uso do 'porque'","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Em 'Ela chorou porque estava triste', a conjuncao 'porque' indica:","alternativa_a":"Causa (oracao subordinada adverbial causal)","alternativa_b":"Consequencia","alternativa_c":"Condicao","alternativa_d":"Concessao","alternativa_e":"Finalidade","resposta_correta":"a","explicacao":"'Porque' como conjuncao subordinativa causal indica a razao/causa da acao da oracao principal. 'Estar triste' e a causa de 'chorar'. Diferencas: 'porque' (conjuncao causal), 'por que' (por + pronome interrogativo), 'por que' (por qual motivo em interrogativa indireta), 'porquê' (substantivo: o porquê), 'por quê' (final de frase interrogativa).","resposta":""},
  {"id":"4202","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Social","subtema":"Reconhecimento","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Axel Honneth, em sua teoria do reconhecimento, identifica tres formas de reconhecimento intersubjetivo:","alternativa_a":"Amor (familia/amizade), direito (reconhecimento juridico) e estima social (realizacoes)","alternativa_b":"Fe, razao e sensacao","alternativa_c":"Individuo, Estado e mercado","alternativa_d":"Producao, distribuicao e consumo","alternativa_e":"Liberdade, igualdade e propriedade","resposta_correta":"a","explicacao":"Honneth, seguindo Hegel, desenvolve tres esferas de reconhecimento necessarias para a realizacao pessoal: (1) Amor — reconhecimento nas relacoes intimas (familia, amizade) que gera autoconfianca; (2) Direito — reconhecimento como sujeito de direitos iguais que gera autorrespeito; (3) Solidariedade/estima social — reconhecimento das contribuicoes especificas do individuo que gera autoestima. Patologias sociais surgem quando o reconhecimento e negado (desrespeito).","resposta":""},
  {"id":"4203","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Famila","subtema":"Arranjos familiares","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As transformacoes na estrutura familiar brasileira nas ultimas decadas incluem:","alternativa_a":"Reducao do tamanho das familias, aumento de familias monoparentais e diversificacao dos arranjos","alternativa_b":"Aumento do numero de filhos por casal","alternativa_c":"Retorno ao modelo patriarcal tradicional","alternativa_d":"Eliminacao dos lacos familiares pela urbanizacao","alternativa_e":"Uniformizacao dos arranjos familiares por todo o pais","resposta_correta":"a","explicacao":"Tendencias demograficas e socioculturais transformaram a familia brasileira: queda da taxa de fecundidade (de 6 em 1960 para ~1,7 em 2020), aumento de familias monoparentais (especialmente chefiadas por mulheres), casais sem filhos, familias recompostas (divorcio e novo casamento), unioes homoafetivas reconhecidas juridicamente desde 2011, e coabitacao antes do casamento.","resposta":""},
  {"id":"4204","tipo":"multipla","disciplina":"Matematica","tema":"Funcoes","subtema":"Funcao inversa","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A funcao inversa de f(x) = 2x + 1 e:","alternativa_a":"f^-1(x) = (x-1)/2","alternativa_b":"f^-1(x) = (x+1)/2","alternativa_c":"f^-1(x) = 2x - 1","alternativa_d":"f^-1(x) = x/2 + 1","alternativa_e":"f^-1(x) = 1/(2x+1)","resposta_correta":"a","explicacao":"Para encontrar a inversa: y = 2x + 1 -> x = (y-1)/2 -> troca x por y: f^-1(x) = (x-1)/2.","resposta":""},
  {"id":"4205","tipo":"multipla","disciplina":"Matematica","tema":"Trigonometria","subtema":"Equacoes trigonometricas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O valor de cos(0 grau) + sen(90 graus) + tan(45 graus) e:","alternativa_a":"3","alternativa_b":"1","alternativa_c":"2","alternativa_d":"0","alternativa_e":"raiz(2)+1","resposta_correta":"a","explicacao":"cos(0) = 1; sen(90) = 1; tan(45) = 1. Soma = 1 + 1 + 1 = 3.","resposta":""},
  {"id":"4206","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Pendulo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O periodo de um pendulo simples depende principalmente de:","alternativa_a":"O comprimento do fio e a gravidade local (nao depende da massa nem da amplitude para pequenas oscilacoes)","alternativa_b":"A massa do pendulo e a gravidade","alternativa_c":"A amplitude de oscilacao e a massa","alternativa_d":"O comprimento do fio e a massa","alternativa_e":"A frequencia de oscilacao e o comprimento","resposta_correta":"a","explicacao":"T = 2*pi * raiz(L/g). O periodo do pendulo simples depende apenas do comprimento L do fio e da aceleracao da gravidade g. Nao depende da massa nem da amplitude (para pequenas oscilacoes, <15 graus). Isso foi observado por Galileu (segundo a lenda, olhando os incensarios oscilando na catedral de Pisa). Galileu usou o pendulo para medir o tempo.","resposta":""},
  {"id":"4207","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Acidos nucleicos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"As bases nitrogenadas do DNA sao:","alternativa_a":"Adenina, Timina, Guanina e Citosina (A-T, G-C)","alternativa_b":"Adenina, Uracila, Guanina e Citosina","alternativa_c":"Adenina, Timina, Glutamina e Citosina","alternativa_d":"Purina, Pirimidina, Glutamato e Fosfato","alternativa_e":"A, U, G, C e T todas juntas","resposta_correta":"a","explicacao":"O DNA possui quatro bases nitrogenadas: Adenina (A), Timina (T), Guanina (G) e Citosina (C). O pareamento especifico: A-T (2 ligacoes de H) e G-C (3 ligacoes de H). O RNA substitui Timina por Uracila (U). Purina: A e G (anel duplo); Pirimidina: T, C e U (anel simples). A regra de Chargaff: %A = %T e %G = %C no DNA.","resposta":""},
  {"id":"4208","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sangue e hemostasia","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Os eritrocitos (globulos vermelhos, hematies) sao responsaveis por:","alternativa_a":"Transportar O2 pelos pulmoes aos tecidos e CO2 dos tecidos aos pulmoes (via hemoglobina)","alternativa_b":"Defender o organismo contra patogenos","alternativa_c":"Realizar a coagulacao sanguinea","alternativa_d":"Produzir anticorpos","alternativa_e":"Transportar lipidios no sangue","resposta_correta":"a","explicacao":"Os eritrocitos sao as celulas mais abundantes do sangue. Contem hemoglobina (proteina com ferro), que se liga ao O2 nos pulmoes (oxi-hemoglobina) e o libera nos tecidos. Tambem transportam CO2 dos tecidos para os pulmoes (principalmente como HCO3- no plasma). Sao celulas anucleadas em mamiferos, o que aumenta o espaco para hemoglobina.","resposta":""},
]

